const tasksRaw = $('Fetch TASKS.md').first().json.data || JSON.stringify($('Fetch TASKS.md').first().json);
const knowledgeRaw = $('Fetch KNOWLEDGE.md').first().json.data || JSON.stringify($('Fetch KNOWLEDGE.md').first().json);
const commits = $('Fetch Recent Commits').first().json || [];

const tasksLines = String(tasksRaw).split('\n');
const trimmedTasks = [];
let keep = true;
let headerDone = false;
for (const line of tasksLines) {
  if (line.startsWith('## Phase') || line.startsWith('## Section')) {
    headerDone = true;
    const isDone = /COMPLETE|completed|100%/i.test(line);
    keep = !isDone;
  }
  if (!headerDone || keep) trimmedTasks.push(line);
}
const tasks = trimmedTasks.join('\n').slice(0, 15000);

const kLines = String(knowledgeRaw).split('\n');
const frontAndCenter = [];
let inFAC = false;
for (const line of kLines) {
  if (/^#.*Front.and.Center/i.test(line)) inFAC = true;
  if (inFAC) {
    frontAndCenter.push(line);
    if (frontAndCenter.length > 1 && /^---/.test(line)) break;
  }
}
const decisionBlocks = String(knowledgeRaw).split(/(?=^### D\d+)/m);
const recentDecisions = decisionBlocks.slice(-20).join('\n');
const knowledge = (frontAndCenter.join('\n') + '\n\n--- Recent Decisions ---\n' + recentDecisions).slice(0, 10000);

const commitSummary = (Array.isArray(commits) ? commits : []).slice(0, 10).map((c) => `- ${c.commit?.message || 'No message'} (${c.sha?.slice(0,7) || 'n/a'})`).join('\n');

const prompt = `Today starts a new 5-day sprint at Paperwork Labs (Monday kickoff, Friday close).\n\nTASKS.md (active phases only):\n${tasks}\n\nRecent decisions:\n${knowledge}\n\nRecent commits:\n${commitSummary}\n\nCreate a sprint kickoff with sections:\n1) *Sprint Goals*\n2) *Engineering Plan*\n3) *Risk Assessment*\n4) *Strategic Priority*\n5) *Top 3 priorities*`;

return [{ json: { prompt } }];

function sanitizeSlackMrkdwn(text) {
  return String(text || '')
    .replace(/```\w*\n?/g, '```')
    .replace(/^#{1,6}\s+(.+)$/gm, '*$1*')
    .replace(/^[-*_]{3,}\s*$/gm, '')
    .replace(/\*\*(.+?)\*\*/g, '*$1*')
    .replace(/\[([^\]]+)\]\(([^)]+)\)/g, '<$2|$1>')
    .replace(/\n{3,}/g, '\n\n');
}

const output = $json.output || [];
const aiText = output[0]?.content?.find((part) => part.type === 'output_text')?.text || '';
const date = new Date().toISOString().split('T')[0];
const header = '*Sprint Kickoff — ' + date + '*\n\n';
const footer = '\n\n_Thread router: reply with a persona name for a focused take._';
const fallback = ':warning: No output generated. Check workflow logs.';
const body = aiText.trim() ? aiText.trim() : fallback;
const text = sanitizeSlackMrkdwn(header + body + footer);
const condensed = aiText.split('\n').slice(0,2).join(' ');
return [{ json: { text, condensed, date } }];
